Memo for myself: This can only occur if acpi_bus_alloc_gas() fails in bus_alloc_resource_any():

acpi_bus_alloc_gas()
{
    ...
    error = ENOMEM;
    ...
    *res = bus_alloc_resource_any(dev, res_type, rid, RF_ACTIVE | flags);
    if (*res != NULL) {
        *type = res_type;
        error = 0;
    } else
        bus_delete_resource(dev, res_type, *rid);

    return (error);
}
